struct Pin: Identifiable, Equatable {
    let id = UUID()
    var title: String
    var subtitle: String
    var coordinate: CLLocationCoordinate2D
}

// MARK: - Google Map UIViewRepresentable
struct GoogleMapView: UIViewRepresentable {
    @Binding var center: CLLocationCoordinate2D
    @Binding var zoom: Float
    @Binding var pins: [Pin]

    func makeCoordinator() -> Coordinator {
        Coordinator(self)
    }

    func makeUIView(context: Context) -> GMSMapView {
        let camera = GMSCameraPosition.camera(withLatitude: center.latitude, longitude: center.longitude, zoom: zoom)
        let mapView = GMSMapView(frame: .zero, camera: camera)
        mapView.settings.compassButton = true
        mapView.settings.myLocationButton = false
        mapView.isMyLocationEnabled = false
        mapView.delegate = context.coordinator
        context.coordinator.renderPins(on: mapView, pins: pins)
        return mapView
    }

    func updateUIView(_ mapView: GMSMapView, context: Context) {
        let currentCamera = mapView.camera
        let desired = GMSCameraPosition.camera(withTarget: center, zoom: zoom)
        if abs(currentCamera.target.latitude - desired.target.latitude) > 0.0001 ||
            abs(currentCamera.target.longitude - desired.target.longitude) > 0.0001 ||
            abs(currentCamera.zoom - desired.zoom) > 0.01 {
            mapView.animate(to: desired)
        }
        context.coordinator.renderPins(on: mapView, pins: pins)
    }

    final class Coordinator: NSObject, GMSMapViewDelegate {
        var parent: GoogleMapView
        private var markers: [UUID: GMSMarker] = [:]

        init(_ parent: GoogleMapView) {
            self.parent = parent
        }

        func renderPins(on mapView: GMSMapView, pins: [Pin]) {
            let existingIDs = Set(markers.keys)
            let newIDs = Set(pins.map { $0.id })

            let toRemove = existingIDs.subtracting(newIDs)
            for id in toRemove {
                markers[id]?.map = nil
                markers.removeValue(forKey: id)
            }

            for pin in pins {
                if let marker = markers[pin.id] {
                    marker.position = pin.coordinate
                    marker.title = pin.title
                    marker.snippet = pin.subtitle
                } else {
                    let marker = GMSMarker(position: pin.coordinate)
                    marker.title = pin.title
                    marker.snippet = pin.subtitle
                    marker.appearAnimation = .pop
                    marker.map = mapView
                    markers[pin.id] = marker
                }
            }
        }

        func mapView(_ mapView: GMSMapView, didChange position: GMSCameraPosition) {
            parent.center = position.target
            parent.zoom = position.zoom
        }

        func mapView(_ mapView: GMSMapView, didTap marker: GMSMarker) -> Bool {
            mapView.selectedMarker = marker
            return true
        }
    }
}

