final class PaymentsViewModel: ObservableObject {
    @Published var isLoading: Bool = false
    @Published var statusText: String = "Ready."
    @Published var statusIsError: Bool = false
    @Published var isPresentingSheet: Bool = false

    let amountDollars: String = "19.99"
    var paymentSheet: PaymentSheet?

    var paymentButtonTitle: String {
        paymentSheet == nil ? "Load Checkout" : "Present Checkout"
    }

    func prepareAndPresent() {
        if paymentSheet != nil {
            isPresentingSheet = true
            return
        }

        isLoading = true
        statusIsError = false
        statusText = "Preparing demo checkout…"

        DispatchQueue.main.asyncAfter(deadline: .now() + 0.5) {
            let demoClientSecret = "pi_demo_secret_demo_client_secret_not_real"

            var config = PaymentSheet.Configuration()
            config.merchantDisplayName = "Investor Demo, Inc."
            config.allowsDelayedPaymentMethods = false
            config.style = .automatic

            self.paymentSheet = PaymentSheet(paymentIntentClientSecret: demoClientSecret, configuration: config)

            self.isLoading = false
            self.statusText = "Checkout ready (demo). Tap again to present."
            self.isPresentingSheet = false
        }
    }

    func handleCompletion(_ result: PaymentSheetResult) {
        switch result {
        case .completed:
            statusIsError = false
            statusText = "Payment completed (demo result)."
        case .canceled:
            statusIsError = false
            statusText = "Payment canceled."
        case .failed(let error):
            statusIsError = true
            statusText = "Payment failed: \(error.localizedDescription)"
        }
    }
}

struct StripePaymentSheetHost: UIViewControllerRepresentable {
    let paymentSheet: PaymentSheet?
    let onCompletion: (PaymentSheetResult) -> Void

    func makeUIViewController(context: Context) -> HostViewController {
        HostViewController(paymentSheet: paymentSheet, onCompletion: onCompletion)
    }

    func updateUIViewController(_ uiViewController: HostViewController, context: Context) {
        uiViewController.paymentSheet = paymentSheet
        uiViewController.onCompletion = onCompletion
        uiViewController.presentIfNeeded()
    }

    final class HostViewController: UIViewController {
        var paymentSheet: PaymentSheet?
        var onCompletion: ((PaymentSheetResult) -> Void)?
        private var hasPresented = false

        init(paymentSheet: PaymentSheet?, onCompletion: ((PaymentSheetResult) -> Void)?) {
            self.paymentSheet = paymentSheet
            self.onCompletion = onCompletion
            super.init(nibName: nil, bundle: nil)
        }

        required init?(coder: NSCoder) { fatalError("init(coder:) has not been implemented") }

        override func viewDidAppear(_ animated: Bool) {
            super.viewDidAppear(animated)
            presentIfNeeded()
        }

        func presentIfNeeded() {
            guard !hasPresented else { return }
            guard let paymentSheet else { return }
            guard presentedViewController == nil else { return }

            hasPresented = true
            paymentSheet.present(from: self) { [weak self] result in
                self?.onCompletion?(result)
                self?.dismiss(animated: true)
            }
        }
    }
}

